import React from 'react';

const smallChopsData = [
  {
    id: 1,
    name: "The Starter Mark",
    price: "15,000",
    contents: "7 Samosas, 7 Spring rolls, 15 Puff Puff, 10 Mosa (or 5 Money Bags), 4 Chicken",
    image: "https://via.placeholder.com/400x300/111111/D4AF37?text=Starter+Mark" 
  },
  {
    id: 2,
    name: "Signature Platter",
    price: "25,000",
    contents: "A luxury high-volume curation. Perfect for gifting, office meetings, or premium sharing.",
    image: "https://via.placeholder.com/400x300/111111/D4AF37?text=Signature+Platter" 
  },
  {
    id: 3,
    name: "The Owambe Pack",
    price: "150,000",
    contents: "Full Event Catering service for 50 People. The ultimate party selection for luxury gatherings.",
    image: "https://via.placeholder.com/400x300/111111/D4AF37?text=Owambe+Pack" 
  },
  {
    id: 4,
    name: "Customized Platter",
    price: "200,000", // "Starts at" is handled in the text below
    contents: "Bespoke catering tailored to your specific guest list and cravings. Starts at ₦200k.",
    image: "https://via.placeholder.com/400x300/111111/D4AF37?text=Custom+Orders" 
  }
];

function Menu() {
  return (
    <section style={{ backgroundColor: '#000', color: '#fff', padding: '80px 20px' }}>
      
      <h2 style={{ 
        color: '#D4AF37', 
        textAlign: 'center', 
        letterSpacing: '8px', 
        textTransform: 'uppercase', 
        fontSize: '1.6rem', 
        marginBottom: '60px' 
      }}>
        The Collections
      </h2>

      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', 
        justifyContent: 'center', 
        gap: '25px', 
        maxWidth: '1200px', 
        margin: '0 auto' 
      }}>
        
        {smallChopsData.map((pack) => (
          <div key={pack.id} style={{ 
            backgroundColor: '#050505', 
            borderRadius: '12px', 
            overflow: 'hidden', 
            border: '1px solid #111',
            display: 'flex',
            flexDirection: 'column',
            height: '100%'
          }}>
            
            <img 
              src={pack.image} 
              alt={pack.name} 
              style={{ width: '100%', height: '220px', objectFit: 'cover' }} 
            />

            <div style={{ padding: '20px', flexGrow: 1, display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
              <div>
                <h3 style={{ color: '#D4AF37', fontSize: '1.2rem', marginBottom: '12px' }}>
                  {pack.name}
                </h3>
                
                <p style={{ 
                  color: '#E07A5F', 
                  fontSize: '0.8rem', 
                  fontWeight: 'bold', 
                  marginBottom: '20px',
                  lineHeight: '1.5',
                  borderLeft: '2px solid #D4AF37',
                  paddingLeft: '10px'
                }}>
                  {pack.contents}
                </p>
              </div>
              
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <p style={{ color: '#fff', fontSize: '1.3rem', fontWeight: 'bold', margin: 0 }}>
                  {pack.id === 4 ? "Starts ₦" : "₦"}{pack.price.toLocaleString()}
                </p>
                
                <button style={{ 
                  backgroundColor: '#D4AF37', 
                  color: '#000', 
                  border: 'none', 
                  padding: '8px 16px', 
                  borderRadius: '4px', 
                  fontSize: '0.7rem', 
                  fontWeight: 'bold',
                  textTransform: 'uppercase'
                }}>
                  Book
                </button>
              </div>
            </div>
          </div>
        ))}

      </div>
    </section>
  );
}

export default Menu;
